import{_ as e,o as t,c as E,a1 as a}from"./chunks/framework.C-iSDJMk.js";const h="/WoW_Guides/assets/nullaeus.Q5i6tcUm.png",l="/WoW_Guides/assets/tormentsrise.DKjCQBEt.jpg",p="data:image/jpeg;base64,",B="data:image/jpeg;base64,",r="data:image/jpeg;base64,",H="data:image/jpeg;base64,",s="/WoW_Guides/assets/razorshellravager.CFEi9iti.png",i="data:image/jpeg;base64,",o="data:image/jpeg;base64,",g="data:image/jpeg;base64,",Q="data:image/jpeg;base64,",U="/WoW_Guides/assets/enslavedvoidcaster.Sc4iDO0h.jpg",n="data:image/jpeg;base64,",S="data:image/jpeg;base64,",c="data:image/jpeg;base64,",w="data:image/jpeg;base64,",x="/WoW_Guides/assets/arcanovoidconstruct.COngmwty.jpg",I=JSON.parse('{"title":"12.0(S1)探究死敵: 努萊厄斯","description":"","frontmatter":{},"headers":[],"relativePath":"WoW/Delves/Nullaeus.md","filePath":"WoW/Delves/Nullaeus.md"}'),d={name:"WoW/Delves/Nullaeus.md"};function k(F,A,q,R,b,J){return t(),E("div",null,[...A[0]||(A[0]=[a('<h1 id="_12-0-s1-探究死敵-努萊厄斯" tabindex="-1">12.0(S1)探究死敵: 努萊厄斯 <a class="header-anchor" href="#_12-0-s1-探究死敵-努萊厄斯" aria-label="Permalink to &quot;12.0(S1)探究死敵: 努萊厄斯&quot;">​</a></h1><p><img src="'+h+'" alt="nullaeus"> 最後編輯時間: 2026/07/14</p><h2 id="簡介" tabindex="-1">簡介 <a class="header-anchor" href="#簡介" aria-label="Permalink to &quot;簡介&quot;">​</a></h2><p>探究折磨高地，位於<strong>虛無風暴(座標: 61.2 71.2)</strong>。</p><p><img src="'+l+'" alt="tormentsrise"></p><p>機制簡單，賽季初期挑戰的主要難點在於近戰攻擊 ，坦克或治療玩家明顯較有優勢。</p><p>?難度與??難度除了傷害與血量有差以外，機制幾乎沒有變化。??難度中技能<strong>虛無空虛</strong>若成功施法，玩家會受到秒殺傷害，<strong>空無區域</strong>的覆蓋會變得無縫接軌。</p><p>瓦麗拉設置為治療，能幫忙驅散dot<strong>吞噬精華</strong>和移除小怪的流血<strong>鋸齒撕扯</strong>。戰鬥珍品建議選擇<strong>星辰披肩</strong>，殘血時能提供護盾，同時擊飛周圍目標附帶易傷，通用珍品則選<strong>時光佚失敕令</strong>，機率刷新護罩，除了可提供護盾，還能提升移速、技能cd速度與施法速度，同時敵人在護罩內能受到相反效果。</p><h2 id="指南" tabindex="-1">指南 <a class="header-anchor" href="#指南" aria-label="Permalink to &quot;指南&quot;">​</a></h2><p><strong>虛無空虛</strong>必斷。<strong>吞噬精華</strong>可被治療瓦麗拉驅散。</p><p>近戰攻擊造成6萬傷害(?難度)/12萬傷害(??難度)。<strong>內爆打擊</strong>為坦克專精挑戰時獨有技能，常規爆坦技。<strong>虛無空虛</strong>造成33萬傷害(?難度)/秒殺傷害(??難度)。</p><p>血量剩餘75%、50%、25%時轉階段，努萊厄斯施放 <span class="tooltip"><strong>寂滅護罩</strong><span class="tooltiptext"><img src="'+p+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>寂滅護罩</strong><br><em>瞬發</em><br> 努萊厄斯以虛無能量保護自身，受到的所有傷害降低100%。 </span></span> ，免疫所有傷害且無法被選中持續30秒，並引導<strong>虛無球</strong>新增一個持續至戰鬥結束的效果，同時召喚小怪。引導結束即會再次加入戰鬥，和小怪存活與否無關。</p><ul><li><img src="'+B+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>內爆打擊</strong>: 對目標造成高額傷害。<br> (15碼/2.5秒施法/鋼條/物理傷害)</li><li><img src="'+r+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>虛無空虛</strong>: 100碼aoe。<br> (3秒施法/可打斷/暗影傷害)</li><li><img src="'+H+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>吞噬精華</strong>: 對目標施加dot，18秒內每2秒造成傷害。<br> (50碼/2.5秒施法/鋼條/暗影傷害/可驅散)</li></ul><h3 id="第一次中場" tabindex="-1">第一次中場 <a class="header-anchor" href="#第一次中場" aria-label="Permalink to &quot;第一次中場&quot;">​</a></h3><p>召喚2隻<strong>刃殼劫毀者</strong>，飛撲技能<strong>尖刺之躍</strong>可被躲避。還擁有施加高額流血的技能<strong>鋸齒撕扯</strong>，該技能只有15碼，而且是點名最近目標，適當調整距離可規避或讓瓦麗拉承受。2隻不會同時放同個技能且受控制效果影響。</p><p><img src="'+s+'" alt="razorshellravager"></p><ul><li><p><img src="'+i+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>尖刺之躍</strong>: 於目標位置刷新4碼地板技，施法成功時飛躍至該處。<br> (60碼/3秒施法/鋼條/自然傷害)</p></li><li><p><img src="'+o+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>鋸齒撕扯</strong>: 對目標施加dot，每3秒造成傷害。<br> (15碼/1.5秒施法/鋼條/物理傷害)</p></li><li><p>第一個<strong>虛無球</strong>效果：週期性以<strong>空無區域</strong> 覆蓋約1/3範圍場地，區域內每秒造成傷害。可能連續選擇同個區域覆蓋。</p></li></ul><h3 id="第二次中場" tabindex="-1">第二次中場 <a class="header-anchor" href="#第二次中場" aria-label="Permalink to &quot;第二次中場&quot;">​</a></h3><p>召喚7隻<strong>吐液蜱</strong>，會遠程對目標疊加<strong>含毒噴吐</strong>，可被控制效果影響。</p><p><img src="'+g+'" alt="spittingtick"></p><ul><li><p><img src="'+Q+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>含毒噴吐</strong>: 對目標施加dot，8秒內每2秒造成傷害。<br> (50碼/3秒施法/鋼條/自然傷害/可疊加)</p></li><li><p>第二個<strong>虛無球</strong>效果：刷新一個<strong>重力井</strong>，會移動的黑洞，50碼內玩家會持續受到吸引，引力會隨距離縮短而增加，中心區域每0.5秒造成傷害。</p></li></ul><h3 id="第三次中場" tabindex="-1">第三次中場 <a class="header-anchor" href="#第三次中場" aria-label="Permalink to &quot;第三次中場&quot;">​</a></h3><p>召喚1隻<strong>被奴役的虛無法師</strong>，血量有點高，會不斷施放<strong>暗影箭</strong>造成5萬傷害，偶爾還會施放<strong>暗影暴擊</strong>迫使玩家移動，以及詛咒技能<strong>遲疑詛咒</strong>。雖然前兩招皆可被打斷，但不建議這麼做，因為法師的近戰攻擊反而比較痛。</p><p><img src="'+U+'" alt="enslavedvoidcaster"></p><ul><li><p><img src="'+n+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>暗影箭</strong>: 對目標造成傷害。<br> (60碼/2秒施法/可打斷/暗影傷害)</p></li><li><p><img src="'+S+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>暗影暴擊</strong>: 於目標位置刷新地板技。<br> (50碼/3秒施法/可打斷/暗影傷害)</p></li><li><p><img src="'+c+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>遲疑詛咒</strong>: 對目標施加詛咒，5分鐘內降低移速30%。<br> (50碼)</p></li><li><p>第三個<strong>虛無球</strong>效果: <span class="tooltip"><strong>晦影之怒</strong><span class="tooltiptext"><img src="'+w+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>晦影之怒</strong><br><em>瞬發</em><br> 努萊厄斯被虛無能量超載，造成的所有傷害提高10%。此光環可堆疊。 </span></span> ，會週期性疊加增傷10%，需盡快結束戰鬥。若爆發傷害不足很容易出現同時面對法師和努萊厄斯的情況。由於法師血量高且免疫控制效果，建議此處開啟爆發，盡可能在30秒內擊殺法師。</p></li></ul><h2 id="獎勵" tabindex="-1">獎勵 <a class="header-anchor" href="#獎勵" aria-label="Permalink to &quot;獎勵&quot;">​</a></h2><ul><li>首次擊敗任意難度可獲得成就<strong>我的陰暗宿敵</strong>，獎勵頭部塑形<strong>努萊厄斯多曼之眼</strong>，以及<strong>英雄晨曦紋章30個</strong>，且似乎不計入賽季上限。</li><li>完成引導任務扼殺努萊厄斯可獲得玩具<strong>壓倒性勝利</strong>。</li><li>擊敗??難度的努萊厄斯可獲得成就<strong>照亮黑暗</strong>，獎勵頭銜『<strong>惡兆</strong>』。</li><li>達成於賽季期間獨自擊敗的條件，可額外獲得偉業<strong>讓我單挑他: 努萊厄斯</strong>，獎勵坐騎<strong>秘虛傀儡</strong>。</li><li>此外若為區域伺服器前4000名成功獨自擊敗的玩家，則額外獲得偉業<strong>傳說級讓我單挑他: 努萊厄斯</strong>，獎勵頭銜『<strong>努萊厄斯傳奇鎮壓者</strong>』。</li></ul><p><img src="'+x+'" alt="arcanovoidconstruct"></p><h2 id="資料參考" tabindex="-1">資料參考 <a class="header-anchor" href="#資料參考" aria-label="Permalink to &quot;資料參考&quot;">​</a></h2><ul><li><a href="https://www.wowhead.com/" target="_blank" rel="noreferrer">Wowhead</a></li></ul>',30)])])}const K=e(d,[["render",k]]);export{I as __pageData,K as default};
